const rawOutput = $input.first().json.output; 

const cleanOutput = rawOutput.replace(/^```json\s*/i, "").replace(/^```\s*/i, "").replace(/\s*```$/, "");

let jsonData;
try {
    jsonData = JSON.parse(cleanOutput);
} catch (error) {
    jsonData = { error: "Gagal parsing JSON", raw: cleanOutput };
}

return { json: jsonData };

const issues = $input.first().json.issues || [];

return issues.map(issue => ({
  json: issue
}));

const targetFingerprint =
  $('Generate Fingerprint').first().json.fingerprint;

const issues = $input.all();

const duplicates = issues.filter(item =>
  item.json.fields?.customfield_10141 === targetFingerprint
);
return duplicates.map(item => ({
  json: item.json
}));

// 1. Ambil output mentah dari AI Agent
// Pastikan path-nya sesuai, biasanya 'output' atau 'response'
const rawOutput = $input.first().json.output; 

// 2. Bersihkan tanda Markdown (```json dan ```)
// Regex ini menghapus ```json di awal dan ``` di akhir
const cleanOutput = rawOutput.replace(/^```json\s*/i, "").replace(/^```\s*/i, "").replace(/\s*```$/, "");

// 3. Parse string bersih menjadi JSON Object
let jsonData;
try {
    jsonData = JSON.parse(cleanOutput);
} catch (error) {
    // Jika masih gagal, kembalikan error agar bisa dicek
    jsonData = { error: "Gagal parsing JSON", raw: cleanOutput };
}

// 4. Kembalikan data matang
return { json: jsonData };

const base64String = $('Parse Input').first().json.screenshot

// Jika ada data screenshot
if (base64String) {
  return [
    {
      json: $input.first().json, // Teruskan data JSON asli
      binary: {
        data: {
          data: base64String,
          mimeType: 'image/png',
          fileName:  $('Parse Output AI (Duplicate)').first().json.ticket_title.issue_title + '.png'
        }
      }
    }
  ];
}

return [$input.first()];

const feature = $('Parse Output AI').first().json.ticket_title.feature;

const issues = $json.issues || [];

const epic = issues.find(
  i => i.fields.summary.toLowerCase() === feature.toLowerCase()
);

return [
  {
    epicExists: !!epic,
    epicKey: epic?.key || null,
    epicId: epic?.id || null,
    feature
  }
];

